var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"기상! 기상하십시오! 기상!","JPN":"起床！起床してください！起床！","ENG":"Wake up! Rise and shine! Wake up!","TWN":"起床！起床了！起床！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으음...... 바보 주르...... 날 깨우지 마.","JPN":"う～ん……J.O.U.Rのバカ……私を起こさないで。","ENG":"Hngh... Stupid J.O.U.R.... Don't wake me up.","TWN":"唔唔……笨蛋朱爾……別叫我啦。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"알람 시작 10분 경과! 탑승자가 깨어나지 않으므로 응급조치 시퀀스를 기동합니다!","JPN":"アラーム開始から10分経過！搭乗者が起きないため、応急処置シークエンスを起動します！","ENG":"10 minutes have elapsed since the alarm has gone off! Commencing emergency sequence as the passenger has failed to rise from slumber!","TWN":"鬧鐘時間超過10分鐘！由於搭乘者仍未醒來，啟動應急措施程序！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"10... 9... 8...","JPN":"10……9……8……","ENG":"10... 9... 8...","TWN":"10…9…8…"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"5... 4... 3... 2...","JPN":"5……4……3……2……","ENG":"5... 4... 3... 2...","TWN":"5…4…3…2…"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"1......","JPN":"1……","ENG":"1......","TWN":"1……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"알람을 정지합니다. 좋은 하루 되세요.","JPN":"アラームを停止します。良い一日を。","ENG":"Disabling alarm. Have a nice day.","TWN":"關閉鬧鐘，祝您度過美好的一天。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"AI_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐으음...... 팬더야 날아라, 날아...... 헤헤......","JPN":"ふ～ん……パンダちゃん、飛べ、飛べ……へへ……","ENG":"Hmm... Fly panda, fly... Heh...","TWN":"哈啊啊……熊貓，飛吧，飛吧……嘿嘿……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"......응?","JPN":"……あれ？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"아하하~ 사장~ 왜 그런 우스꽝스런 자세로 땀을 흘리고 있어?","JPN":"あはは～社長～何でおかしいポーズで汗かいてるの？","ENG":"Hah hah! Boss! Why are you sweating in such an awkward position?","TWN":"啊哈哈～老闆～你怎麼擺出一個滑稽的姿勢，還流那麼多汗？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"응? 의자가 자폭 카운트 하는 걸 직접 멈췄다고?","JPN":"うん？椅子が自爆カウントしていたから直接止めた？","ENG":"Huh? You stopped the chair from counting down to the self-destruct sequence?","TWN":"嗯？你親自關閉了椅子的自爆倒數計時？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"아아~ 괜찮아~ 주르가 말하는 응급조치는 진동마사지로 내 피로를 풀어주는 거거든~","JPN":"ああ～大丈夫だよ～。J.O.U.Rが言ってる応急処置は、振動マッサージで私の疲労をほぐしてくれるってことだから～。","ENG":"Oh, that's okay. What J.O.U.R. meant by the emergency protocol is a massage. It helps me relax.","TWN":"啊啊～沒事啦～朱爾說的應急措施就是震動按摩啦，幫我消除疲勞用的～"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그래도 감동이네~ 날 깨우지 않고 직접 멈춰주다니~ 역시 사장은 좋은 사람이구나?","JPN":"でも感動したよ～。私を起こさないで止めてくれたなんて～やっぱり社長はいい人なんだね。","ENG":"But I'm so touched! You shut it down without waking me up! You're a nice person, as I thought.","TWN":"不過我好感動啊～你居然沒叫醒我，直接關了鬧鐘～老闆你果然是個好人啊。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음...... 그러고 보니 나 왜 여기 있는 거야......?","JPN":"あれ……そう言えば私、何でここにいるの……？","ENG":"Um... Come to think of it, what am I doing here?","TWN":"嗯……可是我怎麼會在這裡啊……？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};